def solve(*args):
    # Assuming args contains the necessary parameters to handle the signature loading
    if not args:
        return None

    # Extracting the necessary parameters from args
    email_content = args[0]
    signature = args[1] if len(args) > 1 else None

    # Check if the email content is a reply or forward
    if "RE:" in email_content or "FWD:" in email_content:
        if signature:
            # Ensure the signature is appended correctly
            return f"{email_content}\n\n{signature}"
        else:
            return email_content  # No signature to append
    else:
        # For new emails, return the content as is
        return email_content
